// Define a class to represent an account
class Account {
    var id: String
    var balance: Double
    var transactions: [Transaction]

    init(id: String, balance: Double) {
        self.id = id
        self.balance = balance
        self.transactions = []
    }

    func deposit(amount: Double) {
        balance += amount
        let transaction = Transaction(type: .deposit, amount: amount)
        transactions.append(transaction)
    }

    func withdraw(amount: Double) {
        guard amount <= balance else { return }
        balance -= amount
        let transaction = Transaction(type: .withdrawal, amount: amount)
        transactions.append(transaction)
    }
}

// Define a class to represent a transaction
class Transaction {
